package com.panini.back.service; import com.panini.back.dto.AuthDtos.*; import com.panini.back.entity.User; import com.panini.back.repository.UserRepository; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.stereotype.Service; @Service public class AuthService { private final UserRepository users; private final PasswordEncoder encoder; private final JwtService jwt; public AuthService(UserRepository users, PasswordEncoder encoder, JwtService jwt){ this.users=users; this.encoder=encoder; this.jwt=jwt; } public AuthResponse register(RegisterRequest r){ if(users.existsByUsername(r.username)) throw new IllegalArgumentException("Username already exists"); User u=new User(); u.setUsername(r.username); u.setDisplayName(r.displayName==null||r.displayName.isBlank()?r.username:r.displayName); u.setPasswordHash(encoder.encode(r.password)); users.save(u); return new AuthResponse(jwt.generateToken(u.getUsername()), u.getUsername(), u.getDisplayName()); } public AuthResponse login(LoginRequest r){ User u=users.findByUsername(r.username).orElseThrow(()->new IllegalArgumentException("Bad credentials")); if(!encoder.matches(r.password,u.getPasswordHash())) throw new IllegalArgumentException("Bad credentials"); return new AuthResponse(jwt.generateToken(u.getUsername()), u.getUsername(), u.getDisplayName()); } }
